import{_ as n}from"./chunks/subs-grants-king.Bdji-M7h.js";import{_ as e,o as s,c as t,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Grant Premium to Your Alliances (King)","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/kingdom-grants.md","filePath":"subscriptions/kingdom-grants.md"}'),i={name:"subscriptions/kingdom-grants.md"};function r(l,a,p,g,c,h){return s(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="grant-premium-to-your-alliances-king" tabindex="-1">Grant Premium to Your Alliances (King) <a class="header-anchor" href="#grant-premium-to-your-alliances-king" aria-label="Permalink to &quot;Grant Premium to Your Alliances (King)&quot;">​</a></h1><p>If your <strong>kingdom</strong> has a premium plan, you can share it with alliances inside your kingdom by offering them a <strong><a href="./../getting-started/glossary.html#grant">grant</a></strong>. A grant lets an alliance use the kingdom&#39;s premium plan (and eligible features) without buying its own. This guide is for <strong>Kings</strong> (and Supreme Admins acting on a kingdom).</p><blockquote><p>A grant is an <strong>offer</strong>. It only takes effect once the alliance <strong>accepts</strong> it — see <a href="./accept-grant.html">Accept a Premium Offer</a>. Offering a grant does not, by itself, make an alliance premium.</p></blockquote><h2 id="before-you-start" tabindex="-1">Before you start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before you start&quot;">​</a></h2><ul><li>Your kingdom must be on a <strong>premium</strong> kingdom plan (a free kingdom can&#39;t grant).</li><li>You manage grants from your <strong>kingdom detail page</strong> (open <strong>Kingdoms</strong>, then your kingdom).</li></ul><p><img src="'+n+`" alt="Grant and allocation manager on the kingdom page"></p><h2 id="how-many-alliances-can-i-grant-to" tabindex="-1">How many alliances can I grant to? <a class="header-anchor" href="#how-many-alliances-can-i-grant-to" aria-label="Permalink to &quot;How many alliances can I grant to?&quot;">​</a></h2><p>The number of grant &quot;slots&quot; you have <strong>comes from your kingdom&#39;s plan</strong> — it isn&#39;t a fixed universal number. A free kingdom plan has none; a premium kingdom plan includes a set number of slots.</p><p><strong>To see your limit, check your Subscription &amp; Usage panel</strong> — the grant slots appear there as one of your resources, showing how many you&#39;ve used and how many you have. If you try to offer more grants than your plan allows, the app stops you with a &quot;grant limit reached&quot; message.</p><h2 id="offering-a-grant" tabindex="-1">Offering a grant <a class="header-anchor" href="#offering-a-grant" aria-label="Permalink to &quot;Offering a grant&quot;">​</a></h2><ol><li>On your kingdom detail page, open the grant manager.</li><li>Choose the <strong>alliance</strong> to grant to.</li><li>Confirm the offer.</li></ol><p>The offer is now <strong>pending</strong> — waiting for that alliance&#39;s leader (or co-leader) to accept. Nothing changes for the alliance until they do.</p><h2 id="the-life-of-a-grant" tabindex="-1">The life of a grant <a class="header-anchor" href="#the-life-of-a-grant" aria-label="Permalink to &quot;The life of a grant&quot;">​</a></h2><p>A grant moves through a clear set of states:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        King offers a grant</span></span>
<span class="line"><span>                │</span></span>
<span class="line"><span>                ▼</span></span>
<span class="line"><span>           ┌─────────┐</span></span>
<span class="line"><span>           │ PENDING │  ── waiting for the alliance to decide</span></span>
<span class="line"><span>           └─────────┘</span></span>
<span class="line"><span>             │      │</span></span>
<span class="line"><span>   alliance  │      │  alliance</span></span>
<span class="line"><span>   accepts   │      │  rejects</span></span>
<span class="line"><span>             ▼      ▼</span></span>
<span class="line"><span>        ┌────────┐  ┌──────────┐</span></span>
<span class="line"><span>        │ ACTIVE │  │ REJECTED │  ── offer declined; no effect</span></span>
<span class="line"><span>        └────────┘  └──────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>   ┌─────────┴───────────┐</span></span>
<span class="line"><span>   │                     │</span></span>
<span class="line"><span> King                 alliance</span></span>
<span class="line"><span> revokes              gives it back</span></span>
<span class="line"><span>   │                     │</span></span>
<span class="line"><span>   ▼                     ▼</span></span>
<span class="line"><span>        ┌──────────────────────┐</span></span>
<span class="line"><span>        │  INACTIVE (ended)     │  ── premium removed from the alliance</span></span>
<span class="line"><span>        └──────────────────────┘</span></span></code></pre></div><ul><li><strong>Pending</strong> — offered, not yet answered.</li><li><strong>Active</strong> — the alliance accepted; the kingdom plan now counts as their <a href="./effective-plan.html">effective plan</a> (shown as &quot;Accepted kingdom grant&quot;).</li><li><strong>Rejected</strong> — the alliance declined. No effect.</li><li><strong>Ended</strong> — a previously active grant was revoked, either by you (the King) or given back by the alliance. It also ends if it expires.</li></ul><h2 id="revoking-a-grant" tabindex="-1">Revoking a grant <a class="header-anchor" href="#revoking-a-grant" aria-label="Permalink to &quot;Revoking a grant&quot;">​</a></h2><p>You can revoke a grant you offered. The alliance can also give a grant back from their side. Either way, when a grant ends:</p><ul><li>The alliance <strong>loses the granted premium</strong> — its <a href="./effective-plan.html">effective plan</a> drops back to whatever it has on its own (its direct plan, or the free tier).</li><li>Any <strong><a href="./allocations.html">allocations</a></strong> you set for that alliance are removed.</li></ul><p>Revoking a grant does <strong>not</strong> affect your normal ability to manage the alliance as its King — it only removes the granted premium and its allocations.</p><h2 id="sharing-limits-not-just-features" tabindex="-1">Sharing limits, not just features <a class="header-anchor" href="#sharing-limits-not-just-features" aria-label="Permalink to &quot;Sharing limits, not just features&quot;">​</a></h2><p>A grant lets several alliances draw on your kingdom plan. If you want to control how much of the kingdom&#39;s limits each granted alliance can use, set <strong><a href="./allocations.html">allocations</a></strong> — per-alliance slices of your kingdom&#39;s quotas.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./accept-grant.html">Accept a Premium Offer</a> — the alliance&#39;s side of this flow.</li><li><a href="./allocations.html">Share Kingdom Quotas with Allocations</a> — divide your limits among granted alliances.</li><li><a href="./effective-plan.html">Which Plan Applies to You</a> — how a grant fits the plan hierarchy.</li></ul>`,24)])])}const f=e(i,[["render",r]]);export{d as __pageData,f as default};
